local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("lang", function(name, str)     local item = string.upper(name)     STRINGS.NAMES[item] = str     STRINGS.CHARACTERS.GENERIC.DESCRIBE[item] = str     STRINGS.RECIPE_DESC[item] = str end) TD.createFn("lang2", function(name, str, str2)     local item = string.upper(name)     STRINGS.NAMES[item] = str     STRINGS.CHARACTERS.GENERIC.DESCRIBE[item] = str2 or str     STRINGS.RECIPE_DESC[item] = str2 or str end) TD.createFn("isCh", function()     if TD.CONST.IS_CHINESE then         return true     end          if not TD.CONST.IS_CHINESE and not TD.CONST.AUTO_TRANSLATE then         return false     end          return TD.isutf8() or TD.isgbk() end) TD.createFn("showStr", function(ch, en)     if TD.isCh() then         return ch or ""     else         return en or ch or ""     end end) TD.createFn("actVis", function()     return "IsActionsVisible" end) TD.createFn("stUpC", function()     return "StopUpdatingComponent" end) TD.createFn("writeDialog", function(sequence, text)     if not TD.isStr(sequence) or not TD.isStr(text) then         return     end          local table = string.td1madao_split(sequence, ".")     local len = #table     local base = _G.STRINGS     TD.fori(table, function(k, v)                  if v == "STRINGS" then                          return false         end         if not TD.isStr(v) then                          return true         end                  if tonumber(v) ~= nil then             v = tonumber(v)         elseif v == "%S" then             v = TD.up(TD.CHAR)         elseif v == "%s" then             v = TD.CHAR         end                  if not base[v] then             if k == len then                 base[v] = text                 return true             else                 base[v] = {}             end         elseif TD.isStr(base[v]) then             base[v] = text             return true         elseif not TD.isTab(base[v]) then                          return true         end         base = base[v]     end)      end) 